import{_ as t,o,c as n,a2 as r}from"./chunks/framework.qS7v0XB7.js";const g=JSON.parse('{"title":"The 12–24 Month Countdown — Relocation Preparation Guide","description":"Month-by-month structured guide for transgender individuals planning international relocation. Three phases covering digital security, savings targets, document strategy, language learning, and final preparation.","frontmatter":{"layout":"doc","title":"The 12–24 Month Countdown — Relocation Preparation Guide","description":"Month-by-month structured guide for transgender individuals planning international relocation. Three phases covering digital security, savings targets, document strategy, language learning, and final preparation."},"headers":[],"relativePath":"prepare/index.md","filePath":"prepare/index.md","lastUpdated":1780601195000}'),a={name:"prepare/index.md"};function i(s,e,l,u,c,d){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="the-12–24-month-countdown" tabindex="-1">The 12–24 Month Countdown <a class="header-anchor" href="#the-12–24-month-countdown" aria-label="Permalink to &quot;The 12–24 Month Countdown&quot;">​</a></h1><p>This guide is for people who have time to plan. If you are not in immediate danger but know you need to leave, start here. Follow the phases in order. Adjust the timeline to your situation — some people move faster, some slower. The goal is to get you out safely with your documents, finances, healthcare, and support network intact.</p><h2 id="phase-1-foundation-months-1–6" tabindex="-1">Phase 1: Foundation (Months 1–6) <a class="header-anchor" href="#phase-1-foundation-months-1–6" aria-label="Permalink to &quot;Phase 1: Foundation (Months 1–6)&quot;">​</a></h2><h3 id="month-1-digital-privacy-operational-security" tabindex="-1">Month 1: Digital Privacy &amp; Operational Security <a class="header-anchor" href="#month-1-digital-privacy-operational-security" aria-label="Permalink to &quot;Month 1: Digital Privacy &amp; Operational Security&quot;">​</a></h3><p>Before you research anything, secure your digital life. If your devices or accounts are monitored, planning your move could put you in more danger.</p><ul><li>[ ] <strong>Install a VPN</strong> on all devices (phone, laptop, tablet). Recommended: Mullvad (€5/month, anonymous payment), ProtonVPN (free tier available). Do not use free VPNs — they often log your data.</li><li>[ ] <strong>Create encrypted backups</strong> of essential documents. Use Cryptomator or Veracrypt for local storage. Proton Drive or Tresorit for encrypted cloud storage.</li><li>[ ] <strong>Set up encrypted messaging</strong> if you have not already. Signal is the gold standard. Teach your key contacts to use it too.</li><li>[ ] <strong>Audit your social media.</strong> Review who can see your posts, friends list, and group memberships. Tighten privacy settings on everything.</li><li>[ ] <strong>Create a &quot;clean&quot; email account</strong> for all relocation planning — nothing connected to your real name at first if possible. Use ProtonMail or Tutanota.</li><li>[ ] <strong>Who not to tell yet:</strong> Do not discuss your plans with anyone who might unintentionally share them. This includes some family members, mutual friends, and coworkers. Establish your digital and operational security before you start telling people.</li></ul><h3 id="month-2-savings-target-calculator" tabindex="-1">Month 2: Savings Target Calculator <a class="header-anchor" href="#month-2-savings-target-calculator" aria-label="Permalink to &quot;Month 2: Savings Target Calculator&quot;">​</a></h3><p>Figure out what you need in the bank. The numbers below are realistic minimums for a single person moving, including visa fees, flights, first/last month rent, and initial living costs.</p><table tabindex="0"><thead><tr><th>Destination</th><th>Estimated Upfront Cost (EUR)</th><th>Visa Fees</th><th>Rent (1-bed, 1st + last month)</th><th>Flights (from most of the world)</th><th>Initial living costs (3 months)</th></tr></thead><tbody><tr><td><strong>Iceland</strong></td><td>€8,000–12,000</td><td>€0–100 (depends on nationality)</td><td>€2,000–3,000</td><td>€500–1,200</td><td>€4,000–6,000</td></tr><tr><td><strong>Portugal</strong></td><td>€5,000–9,000</td><td>€180 (D7/DN visa)</td><td>€1,400–2,400</td><td>€400–1,000</td><td>€3,000–5,000</td></tr><tr><td><strong>Germany</strong></td><td>€4,000–8,000</td><td>€75–100 (visa application)</td><td>€1,400–2,600</td><td>€400–1,000</td><td>€2,500–4,500</td></tr><tr><td><strong>Spain</strong></td><td>€4,500–8,000</td><td>€80–160 (DN visa)</td><td>€1,600–2,800</td><td>€400–1,000</td><td>€2,500–4,500</td></tr><tr><td><strong>Argentina</strong></td><td>€3,000–5,500</td><td>€200 (DN visa)</td><td>€600–1,200</td><td>€800–1,500</td><td>€1,500–2,500</td></tr><tr><td><strong>Canada</strong></td><td>€7,000–14,000</td><td>CAD $1,140 (work permit)</td><td>CAD $2,400–4,000</td><td>€600–1,400</td><td>CAD $5,000–8,000</td></tr><tr><td><strong>New Zealand</strong></td><td>€8,000–15,000</td><td>NZD $750 (work visa)</td><td>NZD $2,600–4,400</td><td>€900–1,800</td><td>NZD $5,000–8,000</td></tr></tbody></table><ul><li>[ ] <strong>Open a dedicated savings account</strong> for relocation funds. If you share finances, think carefully about how to handle this.</li><li>[ ] <strong>Set a monthly savings goal</strong> based on your timeline and target destination.</li><li>[ ] <strong>Research income options</strong> for your target country. Can you work remotely? Are you eligible for any scholarships or worker programmes?</li></ul><h3 id="month-3-document-audit" tabindex="-1">Month 3: Document Audit <a class="header-anchor" href="#month-3-document-audit" aria-label="Permalink to &quot;Month 3: Document Audit&quot;">​</a></h3><ul><li>[ ] <strong>Gather all current documents</strong> in one place: <ul><li>Passport (check expiry — many visas require 6+ months validity)</li><li>National ID card</li><li>Birth certificate</li><li>Current driver&#39;s licence</li><li>Marriage/divorce certificates (if applicable)</li><li>Educational credentials (degrees, certificates, transcripts)</li><li>Professional certifications</li></ul></li><li>[ ] <strong>Check for gender marker consistency.</strong> If your documents have different gender markers, this will cause problems. Plan the order in which you will update them (see Phase 2).</li><li>[ ] <strong>Note what needs updating</strong> before you can use it to apply for visas. For example, if your passport gender marker does not match birth certificate, some countries will reject the application.</li><li>[ ] <strong>Check apostille requirements.</strong> Some countries require certain documents (birth certificates, diplomas) to be apostilled. This can take weeks.</li></ul><h3 id="month-4-income-assessment-visa-research" tabindex="-1">Month 4: Income Assessment &amp; Visa Research <a class="header-anchor" href="#month-4-income-assessment-visa-research" aria-label="Permalink to &quot;Month 4: Income Assessment &amp; Visa Research&quot;">​</a></h3><ul><li><p>[ ] <strong>Research visa options</strong> for your target country. The main categories:</p><ul><li><strong>Digital nomad visa:</strong> For remote workers earning foreign income. Requirements are usually income-based.</li><li><strong>Work visa:</strong> Requires a job offer from an employer in the destination country.</li><li><strong>Student visa:</strong> For enrolling in a degree programme or language course.</li><li><strong>Freelancer/self-employment visa:</strong> For independent professionals (Germany Freiberufler, Portugal D7, Spain DN).</li><li><strong>Working holiday visa:</strong> For young people (usually under 30 or 35). Allows work and travel.</li><li><strong>Family reunification:</strong> If you have a partner who is a citizen or resident.</li></ul></li><li><p>[ ] <strong>Check income thresholds</strong> for digital nomad visas:</p><ul><li><strong>Portugal D8:</strong> €3,040/month minimum (2024 rate)</li><li><strong>Germany Freiberufler:</strong> Variable, no fixed threshold but typically €2,500+/month is expected</li><li><strong>Spain Digital Nomad:</strong> €2,646/month minimum (2024 rate)</li><li><strong>Iceland:</strong> Very limited options for non-EU citizens. Remote work visa up to 18 months but requires strong income (typically €5,000+/month)</li><li><strong>Argentina Digital Nomad:</strong> No fixed minimum but need to show sufficient funds</li><li><strong>Croatia Digital Nomad Visa:</strong> €2,540/month minimum (2024 rate)</li><li><strong>Greece Digital Nomad Visa:</strong> €3,500/month minimum (2024 rate)</li></ul></li></ul><h3 id="month-5-healthcare-research" tabindex="-1">Month 5: Healthcare Research <a class="header-anchor" href="#month-5-healthcare-research" aria-label="Permalink to &quot;Month 5: Healthcare Research&quot;">​</a></h3><ul><li><p>[ ] <strong>Research healthcare system</strong> in your target country. Key questions:</p><ul><li>Is healthcare public or private?</li><li>Can you access HRT on public healthcare, or only private?</li><li>Is informed consent available, or do you need a therapist letter and endocrinologist waitlist?</li><li>How long do wait times typically run for gender-affirming care?</li><li>Are there known trans-friendly clinics in your target city?</li></ul></li><li><p>[ ] <strong>Research international health insurance</strong> that covers gender-affirming care. Options to investigate:</p><ul><li>Cigna Global</li><li>Allianz Worldwide Care</li><li>April International</li><li>GeoBlue</li></ul></li><li><p>[ ] <strong>Talk to your current doctor</strong> (if safe) about getting a 6–12 month supply of HRT before you leave, plus detailed medical records and letters explaining your treatment.</p></li></ul><h3 id="month-6-language-planning-community-research" tabindex="-1">Month 6: Language Planning &amp; Community Research <a class="header-anchor" href="#month-6-language-planning-community-research" aria-label="Permalink to &quot;Month 6: Language Planning &amp; Community Research&quot;">​</a></h3><ul><li><p>[ ] <strong>Start language learning</strong> if you are moving to a non-English-speaking country. Recommended resources:</p><ul><li><strong>Portuguese (Brazilian or European):</strong> Practice Portuguese, Memrise, iTalki tutors</li><li><strong>German:</strong> Deutsche Welle (free), Nicos Weg course, Goethe Institut classes</li><li><strong>Spanish:</strong> Dreaming Spanish, Language Transfer (free), iTalki</li><li><strong>Icelandic:</strong> Icelandic Online (University of Iceland, free), Íslenska fyrir alla</li><li><strong>Realistic timeline:</strong> B1 proficiency in Portuguese/Spanish/German takes approximately 600 hours of study. At 5 hours/week, that is 2.5 years. At 10 hours/week, 15 months. Be realistic about where you will be when you arrive.</li></ul></li><li><p>[ ] <strong>Join online communities</strong> for trans people in your target country. Facebook groups, Reddit (r/transgender, country-specific subs), Discord servers. Do not announce your plans publicly, but observe and ask discreet questions.</p></li><li><p>[ ] <strong>Research cost of living</strong> in your target city using Numbeo and Expatistan.</p></li></ul><h2 id="phase-2-building-months-7–12" tabindex="-1">Phase 2: Building (Months 7–12) <a class="header-anchor" href="#phase-2-building-months-7–12" aria-label="Permalink to &quot;Phase 2: Building (Months 7–12)&quot;">​</a></h2><h3 id="month-7-document-update-strategy" tabindex="-1">Month 7: Document Update Strategy <a class="header-anchor" href="#month-7-document-update-strategy" aria-label="Permalink to &quot;Month 7: Document Update Strategy&quot;">​</a></h3><p>This is one of the hardest parts of relocation as a trans person: your documents may not be consistent, and updating them in the wrong order can create problems.</p><ul><li><p>[ ] <strong>Decide on your document update order.</strong> The general principle:</p><ol><li><strong>Change your name/gender on documents in the country where you have the easiest process first.</strong> This is often not your passport country.</li><li><strong>Passport last,</strong> because changing your passport can out you to authorities and trigger scrutiny when entering other countries.</li><li><strong>Medical records and banking can be done independently</strong> of legal documents in many countries.</li><li><strong>Check the destination country&#39;s rules:</strong> Some countries (e.g., Germany) require your documents to be consistent to grant a visa. Others (e.g., Portugal) are more flexible.</li></ol></li><li><p>[ ] <strong>If updating documents would out you to family or authorities</strong> in your current country, consider whether it is safer to leave documents as they are and plan to change them after arrival. This is valid even if it means arriving with inconsistent documents.</p></li><li><p>[ ] <strong>Get professional advice</strong> from a trans-friendly immigration lawyer or a legal aid organisation like ILGA or TGEU before making changes that could affect your exit.</p></li></ul><h3 id="month-8-international-banking" tabindex="-1">Month 8: International Banking <a class="header-anchor" href="#month-8-international-banking" aria-label="Permalink to &quot;Month 8: International Banking&quot;">​</a></h3><ul><li><p>[ ] <strong>Open an international account</strong> that works across borders:</p><ul><li><strong>Wise:</strong> Best for currency exchange and receiving foreign income. Not a full bank account (no overdraft, limited savings interest). Good for holding 50+ currencies.</li><li><strong>Revolut:</strong> Full EU banking (if you have EU residency) or prepaid card (otherwise). Good for daily spending. Limitations: not all countries accept it for salary deposits; large transfers over €10,000 may be flagged.</li><li><strong>N26:</strong> Full EU bank account (if you have EU residency). Clean app, good for Germany-based planning. Limitations: requires EU address to open.</li><li><strong>If you are from the US:</strong> Consider Charles Schwab (no foreign transaction fees, refunds ATM fees worldwide).</li><li><strong>If you are from the UK:</strong> Monzo and Starling have low or no foreign transaction fees.</li></ul></li><li><p>[ ] <strong>Set up multi-currency accounts</strong> in EUR, USD, and your target currency if different.</p></li><li><p>[ ] <strong>Research transfer methods</strong> for moving larger amounts. Wise is usually the cheapest for mid-size transfers (€1,000–50,000). For larger amounts consider CurrencyFair or OFX.</p></li></ul><h3 id="month-9-remote-work-income-building" tabindex="-1">Month 9: Remote Work Income Building <a class="header-anchor" href="#month-9-remote-work-income-building" aria-label="Permalink to &quot;Month 9: Remote Work Income Building&quot;">​</a></h3><ul><li><p>[ ] <strong>If you are not already remote:</strong> Start building a remote-workable skill set. Popular options:</p><ul><li>Programming/web development</li><li>Digital marketing</li><li>Copywriting/content writing</li><li>Virtual assistance</li><li>Online teaching/TEFL</li><li>Graphic design</li><li>Bookkeeping</li></ul></li><li><p>[ ] <strong>If you are already remote:</strong> Check if your employer allows international work. Many companies restrict working from certain countries due to tax and legal obligations.</p></li><li><p>[ ] <strong>Build a portfolio or freelance profile</strong> on Upwork, Fiverr, or Toptal. Even if you have a regular job, having freelance income can help prove your ability to earn remotely for visa applications.</p></li></ul><h3 id="month-10-housing-research-networks" tabindex="-1">Month 10: Housing Research &amp; Networks <a class="header-anchor" href="#month-10-housing-research-networks" aria-label="Permalink to &quot;Month 10: Housing Research &amp; Networks&quot;">​</a></h3><ul><li><p>[ ] <strong>Research rental markets</strong> in your target city:</p><ul><li>Typical rent for a 1-bedroom in a safe area</li><li>Deposit requirements (usually 1–3 months rent)</li><li>Documents needed to rent (payslips, tax returns, proof of employment)</li><li>Rental scams to watch for</li><li>Whether you need a guarantor in the country</li></ul></li><li><p>[ ] <strong>Start connecting with people</strong> in your target city. LinkedIn, professional networks, LGBTQ+ expat groups. Do not lead with &quot;I need help getting out&quot; — build genuine relationships first.</p></li><li><p>[ ] <strong>Research short-term housing</strong> for when you first arrive (Airbnb, short-term rental, hostel with private room). Aim to have at least 2 weeks of temporary accommodation booked.</p></li></ul><h3 id="month-11-professional-network-job-leads" tabindex="-1">Month 11: Professional Network &amp; Job Leads <a class="header-anchor" href="#month-11-professional-network-job-leads" aria-label="Permalink to &quot;Month 11: Professional Network &amp; Job Leads&quot;">​</a></h3><ul><li><p>[ ] <strong>If you need a work visa:</strong> Start applying for jobs in your target country. The process can take 3–6 months from offer to visa approval.</p></li><li><p>[ ] <strong>If you are on a digital nomad visa:</strong> Build your freelance client base so you have steady income to show when applying.</p></li><li><p>[ ] <strong>Update your CV/resume</strong> to the standards of your target country. Each country has different expectations for document length, format, and content.</p></li><li><p>[ ] <strong>Research trans-friendly employers</strong> in your target country. Some companies have explicit trans-inclusion policies and healthcare benefits.</p></li></ul><h3 id="month-12-mid-point-review" tabindex="-1">Month 12: Mid-Point Review <a class="header-anchor" href="#month-12-mid-point-review" aria-label="Permalink to &quot;Month 12: Mid-Point Review&quot;">​</a></h3><ul><li>[ ] <strong>Review your savings progress.</strong> Are you on track? If not, adjust your timeline or destination.</li><li>[ ] <strong>Reassess your target country.</strong> Have there been legal changes? Check ILGA, TGEU, and Equaldex for updates.</li><li>[ ] <strong>Test your digital security.</strong> Are your encrypted backups working? Is your VPN still active?</li><li>[ ] <strong>Check your passport expiry.</strong> If it expires within 12 months of your planned move, renew it now.</li><li>[ ] <strong>Take a language proficiency test</strong> (if relevant) to see where you stand.</li></ul><h2 id="phase-3-final-preparation-months-13–24" tabindex="-1">Phase 3: Final Preparation (Months 13–24) <a class="header-anchor" href="#phase-3-final-preparation-months-13–24" aria-label="Permalink to &quot;Phase 3: Final Preparation (Months 13–24)&quot;">​</a></h2><h3 id="month-13-tax-residency-planning" tabindex="-1">Month 13: Tax Residency Planning <a class="header-anchor" href="#month-13-tax-residency-planning" aria-label="Permalink to &quot;Month 13: Tax Residency Planning&quot;">​</a></h3><ul><li><p>[ ] <strong>Understand how to break tax residency</strong> in your current country:</p><ul><li><strong>UK:</strong> File HMRC form P85 to claim non-residency. You must spend fewer than 183 days in the UK in the tax year and fewer than 91 days on average over 4 years (the &quot;Sufficient Ties&quot; test).</li><li><strong>US:</strong> US citizens are taxed on worldwide income regardless of residence. You will need to file FBAR (Foreign Bank Account Report) and FATCA forms if you have foreign accounts over certain thresholds. The Foreign Earned Income Exclusion (FEIE) can exempt up to ~$126,500 (2024) of foreign earned income.</li><li><strong>General rule:</strong> Most countries use the 183-day rule — if you spend more than 183 days in a country, you are tax resident there. Plan your move dates carefully.</li><li><strong>Dual tax treaties:</strong> Check if your current and destination countries have a tax treaty to avoid double taxation.</li></ul></li><li><p>[ ] <strong>Set up a professional relationship</strong> with an accountant or tax advisor who understands cross-border tax and trans-specific issues (e.g., costs of gender-affirming care may be tax-deductible in some countries).</p></li></ul><h3 id="month-14-final-document-consistency-check" tabindex="-1">Month 14: Final Document Consistency Check <a class="header-anchor" href="#month-14-final-document-consistency-check" aria-label="Permalink to &quot;Month 14: Final Document Consistency Check&quot;">​</a></h3><ul><li>[ ] <strong>Lay out all your documents</strong> side by side. Check that names and gender markers are consistent enough for your visa application.</li><li>[ ] <strong>If documents are inconsistent:</strong> Prepare a written explanation of why. Some countries accept a cover letter explaining that you are in the process of updating documents and outlining your timeline.</li><li>[ ] <strong>Get any documents notarised, apostilled, or translated</strong> that will be needed for your visa application. Translation requirements vary — some countries require certified translations by approved translators.</li></ul><h3 id="month-15–16-language-immersion-cultural-research" tabindex="-1">Month 15–16: Language Immersion &amp; Cultural Research <a class="header-anchor" href="#month-15–16-language-immersion-cultural-research" aria-label="Permalink to &quot;Month 15–16: Language Immersion &amp; Cultural Research&quot;">​</a></h3><ul><li>[ ] <strong>Intensify language study.</strong> If you can afford it, take a language course in the destination country (even a 2-week intensive course before you move can help enormously).</li><li>[ ] <strong>Research the specific city you are moving to.</strong> Not all cities in a trans-friendly country are equally safe. In Germany, Berlin and Cologne are very different from rural Bavaria or Saxony. In Spain, Barcelona and Madrid have large trans communities; smaller Andalusian towns may be more conservative.</li><li>[ ] <strong>Learn the local trans vocabulary</strong> in the language of your destination. You need to know how to say your pronouns, your identity, and basic healthcare terms.</li></ul><h3 id="month-17–18-application-month" tabindex="-1">Month 17–18: Application Month <a class="header-anchor" href="#month-17–18-application-month" aria-label="Permalink to &quot;Month 17–18: Application Month&quot;">​</a></h3><ul><li>[ ] <strong>Submit your visa application</strong> (work, study, digital nomad, or other).</li><li>[ ] <strong>Book your flight</strong> (research flexible/refundable options in case of delays).</li><li>[ ] <strong>Purchase health insurance</strong> that covers your move and initial period in the destination country.</li><li>[ ] <strong>Arrange accommodation</strong> for at least the first 2 weeks after arrival.</li><li>[ ] <strong>Transfer enough money</strong> to your international account to cover initial costs.</li></ul><h3 id="month-19–20-pre-departure-logistics" tabindex="-1">Month 19–20: Pre-Departure Logistics <a class="header-anchor" href="#month-19–20-pre-departure-logistics" aria-label="Permalink to &quot;Month 19–20: Pre-Departure Logistics&quot;">​</a></h3><ul><li>[ ] <strong>Sort your belongings:</strong> What ships, what flies with you, what gets stored, what gets sold or donated.</li><li>[ ] <strong>Cancel or redirect subscriptions:</strong> Bank statements, utilities, phone contract, insurance, gym membership, streaming services.</li><li>[ ] <strong>Forward mail</strong> (if possible).</li><li>[ ] <strong>Get tax clearance</strong> from your current country&#39;s revenue authority if required.</li><li>[ ] <strong>Research phone options</strong> for your destination country. You may want to get a local SIM immediately on arrival or use an eSIM like Airalo for the first few weeks.</li></ul><h3 id="month-21-informing-your-support-network" tabindex="-1">Month 21: Informing Your Support Network <a class="header-anchor" href="#month-21-informing-your-support-network" aria-label="Permalink to &quot;Month 21: Informing Your Support Network&quot;">​</a></h3><ul><li><p>[ ] <strong>Decide who to tell and when.</strong> This is deeply personal. Some factors to consider:</p><ul><li>Who needs to know for practical reasons (employer, landlord, bank)?</li><li>Who will keep your confidence?</li><li>Who might try to stop you?</li><li>Who will worry and should be reassured after you arrive?</li></ul></li><li><p>[ ] <strong>Do not post on social media</strong> about your move until you are safely in your destination country.</p></li><li><p>[ ] <strong>For those you tell before you go:</strong> Emphasise that this is not up for debate. You are informing them, not asking permission.</p></li></ul><h3 id="month-22-packing-final-medical-prep" tabindex="-1">Month 22: Packing &amp; Final Medical Prep <a class="header-anchor" href="#month-22-packing-final-medical-prep" aria-label="Permalink to &quot;Month 22: Packing &amp; Final Medical Prep&quot;">​</a></h3><ul><li>[ ] <strong>Get your largest possible HRT supply.</strong> Aim for 6–12 months. Some doctors will write a larger prescription if you explain you are moving to a country where access may be delayed.</li><li>[ ] <strong>Get a detailed letter</strong> from your doctor explaining your diagnosis, treatment, and medication list. Get it translated into your destination language if possible.</li><li>[ ] <strong>Get copies of all medical records</strong> (blood test results, clinic letters, surgery records).</li><li>[ ] <strong>Pack your carry-on bag</strong> with: documents, medication (with original labels), phone, charger, change of clothes, snacks, water.</li><li>[ ] <strong>Pack one checked bag</strong> or ship a box ahead. Do not bring so much that you cannot move quickly if something goes wrong.</li></ul><h3 id="month-23–24-departure" tabindex="-1">Month 23–24: Departure <a class="header-anchor" href="#month-23–24-departure" aria-label="Permalink to &quot;Month 23–24: Departure&quot;">​</a></h3><ul><li>[ ] <strong>Check travel restrictions and entry requirements</strong> 72 hours before departure. Some countries change requirements with little notice.</li><li>[ ] <strong>Confirm transit rules</strong> — do you need a transit visa for any connections? Revisit the <a href="/transit/emergency/#step-2-transit-risk-assessment">transit risk assessment on the Emergency page</a>.</li><li>[ ] <strong>Empty your browser history</strong> on any device you are leaving behind.</li><li>[ ] <strong>Leave a copy of your itinerary and emergency contact</strong> with one trusted person (do not share it widely).</li><li>[ ] <strong>Go.</strong> You have done the work. Trust your planning.</li></ul><h2 id="important-notes-on-the-data-sources" tabindex="-1">Important Notes on the Data Sources <a class="header-anchor" href="#important-notes-on-the-data-sources" aria-label="Permalink to &quot;Important Notes on the Data Sources&quot;">​</a></h2><p>The <a href="https://www.equaldex.com/equality-index" target="_blank" rel="noreferrer">Equaldex Equality Index</a> is referenced throughout this site. It measures <strong>LGBTQ+ equality broadly</strong> — it includes sexual orientation and gender identity rights but does not specifically measure trans-specific protections. A country with a high Equaldex score does not necessarily have good trans-specific healthcare, gender recognition, or community safety. Wherever possible, use trans-specific sources (TGEU, ILGA trans rights data, community reports) in addition to Equaldex.</p><p><em>Last verified: June 2026. Costs and visa fees change. Check official government websites for current income thresholds, visa fees, and processing times before making financial commitments.</em></p>',52)])])}const m=t(a,[["render",i]]);export{g as __pageData,m as default};
